#include <stdio.h>
#include <string.h>
#define MOD 998244353
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        char S[100005];
        scanf("%s", S);
        int n = strlen(S);
        long long dp0 = 1, dp1 = 1, dp2;
        for(int i=2;i<=n;i++){
            if(S[i-2]!=S[i-1]) dp2 = (dp1 + dp0) % MOD;
            else dp2 = dp1;
            dp0 = dp1;
            dp1 = dp2;
        }
        printf("%lld\n", dp1 % MOD);
    }
    return 0;
}

