import sys
MOD = 998244353

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    out = []
    idx = 1
    for _ in range(t):
        s = data[idx]; idx += 1
        dp0, dp1 = 1, 1
        n = len(s)
        for i in range(2, n+1):
            if s[i-2] != s[i-1]:
                dp2 = (dp1 + dp0) % MOD
            else:
                dp2 = dp1
            dp0, dp1 = dp1, dp2
        out.append(str(dp1 % MOD))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

